   219	    private void validateContentLengthRange(String policyBase64, int contentLength) {
   220	        try {
   221	            String decoded = new String(java.util.Base64.getDecoder().decode(policyBase64), StandardCharsets.UTF_8);
   222	            // Parse conditions array from the policy JSON to find content-length-range
   223	            int condIdx = decoded.indexOf("\"conditions\"");
   224	            if (condIdx < 0) {
   225	                return;
   226	            }
   227	            // Look for content-length-range condition: ["content-length-range", min, max]
   228	            String lower = decoded.toLowerCase(Locale.ROOT);
   229	            int rangeIdx = lower.indexOf("content-length-range");
   230	            if (rangeIdx < 0) {
   231	                return;
   232	            }
   233	            // Find the enclosing array bracket
   234	            int bracketStart = decoded.lastIndexOf('[', rangeIdx);
   235	            int bracketEnd = decoded.indexOf(']', rangeIdx);
   236	            if (bracketStart < 0 || bracketEnd < 0) {
   237	                return;
   238	            }
   239	            String rangeArray = decoded.substring(bracketStart, bracketEnd + 1);
   240	            // Extract min and max values
   241	            String[] tokens = rangeArray.replaceAll("[\\[\\]\"]", "").split(",");
   242	            if (tokens.length >= 3) {
   243	                long min = Long.parseLong(tokens[1].trim());
   244	                long max = Long.parseLong(tokens[2].trim());
   245	                if (contentLength < min || contentLength > max) {
   246	                    throw new AwsException("EntityTooLarge",
   247	                            "Your proposed upload exceeds the maximum allowed size.", 400);
   248	                }
   249	            }
   250	        } catch (AwsException e) {
   251	            throw e;
   252	        } catch (Exception e) {
   253	            // If policy parsing fails, skip validation (match AWS lenient behavior for emulator)
   254	            LOG.debugv("Failed to parse presigned POST policy: {0}", e.getMessage());
   255	        }
   256	    }
