   258	    private static String extractBoundary(String contentType) {
   259	        if (contentType == null) {
   260	            return null;
   261	        }
   262	        for (String part : contentType.split(";")) {
   263	            String trimmed = part.trim();
   264	            if (trimmed.toLowerCase(Locale.ROOT).startsWith("boundary=")) {
   265	                String boundary = trimmed.substring("boundary=".length()).trim();
   266	                if (boundary.startsWith("\"") && boundary.endsWith("\"")) {
   267	                    boundary = boundary.substring(1, boundary.length() - 1);
   268	                }
   269	                return boundary;
   270	            }
   271	        }
   272	        return null;
   273	    }
