   275	    private static List<byte[]> splitMultipartParts(byte[] body, byte[] boundary) {
   276	        java.util.ArrayList<byte[]> parts = new java.util.ArrayList<>();
   277	        int pos = indexOf(body, boundary, 0);
   278	        if (pos < 0) {
   279	            return parts;
   280	        }
   281	        // Skip past the first boundary line
   282	        pos += boundary.length;
   283	        // Skip the CRLF or -- after boundary
   284	        if (pos < body.length - 1 && body[pos] == '-' && body[pos + 1] == '-') {
   285	            return parts; // closing boundary immediately
   286	        }
   287	        if (pos < body.length - 1 && body[pos] == '\r' && body[pos + 1] == '\n') {
   288	            pos += 2;
   289	        }
   290	
   291	        while (pos < body.length) {
   292	            int nextBoundary = indexOf(body, boundary, pos);
   293	            if (nextBoundary < 0) {
   294	                break;
   295	            }
   296	            parts.add(Arrays.copyOfRange(body, pos, nextBoundary));
   297	            pos = nextBoundary + boundary.length;
   298	            // Check for closing boundary --
   299	            if (pos < body.length - 1 && body[pos] == '-' && body[pos + 1] == '-') {
   300	                break;
   301	            }
   302	            // Skip CRLF after boundary
   303	            if (pos < body.length - 1 && body[pos] == '\r' && body[pos + 1] == '\n') {
   304	                pos += 2;
   305	            }
   306	        }
   307	        return parts;
   308	    }
