   332	    private static String extractHeaderValue(String headers, String headerName) {
   333	        String lowerHeaders = headers.toLowerCase(Locale.ROOT);
   334	        String lowerName = headerName.toLowerCase(Locale.ROOT) + ":";
   335	        int idx = lowerHeaders.indexOf(lowerName);
   336	        if (idx < 0) {
   337	            return null;
   338	        }
   339	        int valueStart = idx + lowerName.length();
   340	        int lineEnd = headers.indexOf('\r', valueStart);
   341	        if (lineEnd < 0) {
   342	            lineEnd = headers.indexOf('\n', valueStart);
   343	        }
   344	        if (lineEnd < 0) {
   345	            lineEnd = headers.length();
   346	        }
   347	        return headers.substring(valueStart, lineEnd).trim();
