   350	    private static String extractDispositionParam(String disposition, String paramName) {
   351	        String search = paramName + "=";
   352	        int idx = disposition.indexOf(search);
   353	        if (idx < 0) {
   354	            return null;
   355	        }
   356	        int valueStart = idx + search.length();
   357	        if (valueStart >= disposition.length()) {
   358	            return null;
   359	        }
   360	        if (disposition.charAt(valueStart) == '"') {
   361	            valueStart++;
   362	            int valueEnd = disposition.indexOf('"', valueStart);
   363	            if (valueEnd < 0) {
   364	                return disposition.substring(valueStart);
   365	            }
   366	            return disposition.substring(valueStart, valueEnd);
   367	        } else {
   368	            int valueEnd = disposition.indexOf(';', valueStart);
   369	            if (valueEnd < 0) {
   370	                valueEnd = disposition.length();
   371	            }
   372	            return disposition.substring(valueStart, valueEnd).trim();
   373	        }
   374	    }
