    private Response handleListObjectVersions(String bucket, String prefix, Integer maxKeys) {
        int max = (maxKeys != null && maxKeys > 0) ? maxKeys : 1000;
        List<S3Object> versions = s3Service.listObjectVersions(bucket, prefix, max);
